// src/ADMIN/ManageOfficers.js
import React, { useEffect, useState } from 'react';
import Swal from 'sweetalert2';
import { Link } from 'react-router-dom';
import './manageOfficers.css'; // Ensure you create this CSS file for styling

const ManageOfficers = () => {
  const [officers, setOfficers] = useState([]);

  useEffect(() => {
    // Fetch officers data from API
    const fetchOfficers = async () => {
      try {
        const response = await fetch('/api/officers'); // Update with your API endpoint
        const data = await response.json();
        setOfficers(data);
      } catch (error) {
        console.error('Error fetching officers:', error);
      }
    };

    fetchOfficers();
  }, []);

  const confirmDelete = (officerId) => {
    Swal.fire({
      title: 'Are you sure?',
      text: "You won't be able to revert this!",
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#3085d6',
      cancelButtonColor: '#d33',
      confirmButtonText: 'Yes, delete it!',
    }).then(async (result) => {
      if (result.isConfirmed) {
        try {
          await fetch(`/api/officers/${officerId}`, { method: 'DELETE' });
          setOfficers(officers.filter(officer => officer.id !== officerId));
          Swal.fire('Deleted!', 'The officer has been deleted.', 'success');
        } catch (error) {
          console.error('Error deleting officer:', error);
          Swal.fire('Error!', 'There was an error deleting the officer.', 'error');
        }
      }
    });
  };

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      <table className="officers-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Role</th>
            <th>Email</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {officers.map(officer => (
            <tr key={officer.id}>
              <td>{officer.id}</td>
              <td>{officer.name}</td>
              <td>{officer.role}</td>
              <td>{officer.email}</td>
              <td>
                <Link to={`/admin/update-officer/${officer.id}`} className="btn btn-primary">Update</Link>
                <button onClick={() => confirmDelete(officer.id)} className="btn btn-danger">Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
